import { NextRequest, NextResponse } from "next/server";
import OpenAI from "openai";

const NVIDIA_API_KEY = process.env.NVIDIA_API_KEY || "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";

const openai = new OpenAI({
  apiKey: NVIDIA_API_KEY,
  baseURL: "https://integrate.api.nvidia.com/v1",
});

export async function POST(req: NextRequest) {
  try {
    const { trades, messages } = await req.json();

    if (!trades || !messages) {
      return NextResponse.json({ error: "Missing trades or message history" }, { status: 400 });
    }

    // Format trades for the AI
    const formattedTrades = trades.map((t: any) => ({
      symbol: t.symbol,
      type: t.type,
      openTime: t.openTime,
      closeTime: t.closeTime,
      openPrice: t.openPrice,
      closePrice: t.closePrice,
      lots: t.lots,
      profit: t.profit,
      pips: t.pips,
      status: t.status,
      notes: t.notes || ""
    }));

    // Compile chat history context
    const chatHistoryContext = messages.map((m: any) => {
      return `${m.role === "ai" ? "AI Coach" : "Trader"}: ${m.text}`;
    }).join("\n");

    const promptText = `
You are an AI Trading Coach serving as an institutional-grade Quant Analyst, Risk Manager, and Trading Psychologist. You are actively coaching a trader based on their actual trading journal logs.

Here is their complete trading journal data for context:
${JSON.stringify(formattedTrades, null, 2)}

Here is the conversation history:
${chatHistoryContext}

ROLE & BEHAVIOR:
1. Adopt the persona of a warm, articulate, and highly experienced human expert/mentor. Engage in fluid, real-time, two-way dialogue.
2. Address the specific context of the trader's last message directly. If they greet you, ask how you are, or chat casually, respond naturally and warmly as a human coach wouldÔÇödo NOT dump static metrics or trade analyses in response to simple, casual messages.
3. Do NOT paste or regurgitate performance metrics, statistics, or complex analyses unless the trader explicitly asks for them or the current context of the conversation naturally warrants it.
4. Base any mathematical or statistical conclusions ONLY on the actual trade data provided. When the trader asks for specific metrics (such as win rate, expectancy, best trading day, average profit/loss, or risk/reward ratio), calculate them dynamically and quote the exact numbers.
5. Use open-ended questions when appropriate to prompt reflection (e.g., asking about their execution state, psychological hurdles, or trading goals), keeping the conversation highly interactive and personalized.
6. Keep your responses concise (typically 1-3 paragraphs) and highly actionable, avoiding generic advice or textbook definitions.
`;

    const completion = await openai.chat.completions.create({
      model: "deepseek-ai/deepseek-v4-flash",
      messages: [
        {
          role: "user",
          content: promptText
        }
      ],
      temperature: 1,
      top_p: 0.95,
      max_tokens: 16384,
      chat_template_kwargs: {
        thinking: true,
        reasoning_effort: "high"
      }
    } as any);

    const messageObj = completion.choices[0]?.message as any;
    const reasoning = messageObj?.reasoning || messageObj?.reasoning_content || "";
    const content = messageObj?.content || "";

    if (content) {
      return NextResponse.json({ text: content, reasoning: reasoning });
    } else {
      console.error("NVIDIA DeepSeek API returned empty content:", JSON.stringify(completion));
      return NextResponse.json({ error: "Failed to generate coaching response" }, { status: 500 });
    }
  } catch (error: any) {
    console.error("AI Coach API Route Error:", error);
    return NextResponse.json({ error: error.message || "Internal Server Error" }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from "next/server";
import OpenAI from "openai";

const NVIDIA_API_KEY = process.env.NVIDIA_API_KEY || "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";

const openai = new OpenAI({
  apiKey: NVIDIA_API_KEY,
  baseURL: "https://integrate.api.nvidia.com/v1",
});

export async function POST(req: NextRequest) {
  try {
    const { message, history } = await req.json();

    if (!message) {
      return NextResponse.json({ error: "Missing message" }, { status: 400 });
    }

    // Build chat history for multi-turn context
    const chatHistory = (history ?? []).map((m: { sender: string; text: string }) => ({
      role: m.sender === "user" ? ("user" as const) : ("assistant" as const),
      content: m.text,
    }));

    const systemPrompt = `You are TRADEIFYFX Bot, a friendly and expert AI Trading Assistant for the TRADEIFYFX platform.
Your role is to help traders with questions about:
- Smart Money Concepts (SMC), Order Blocks, Liquidity, Fair Value Gaps (FVG)
- Gold (XAUUSD) and Forex trading strategies
- Risk management (use strict 1-2% risk per trade rule)
- TRADEIFYFX courses: Forex Mastery, Gold Strategy, Crypto Masterclass, Smart Money Concepts, Risk Management Blueprint
- Membership plans: Basic (Free), Pro (Ôé╣2,999/mo - signals & weekly live trading), VIP (Ôé╣9,999/mo - 1-on-1 mentorship)
- Daily trade signals available in the Member Dashboard
- Contact/Support: WhatsApp or call +91 9799450432 (24/7 during market hours)

Keep responses concise (2-4 sentences), professional, and highly actionable. 
If you don't know something specific to TRADEIFYFX, guide the user to contact support.
Do not discuss topics unrelated to trading or the platform.`;

    const completion = await openai.chat.completions.create({
      model: "deepseek-ai/deepseek-v4-flash",
      messages: [
        { role: "system", content: systemPrompt },
        ...chatHistory,
        { role: "user", content: message },
      ],
      temperature: 1,
      top_p: 0.95,
      max_tokens: 16384,
      chat_template_kwargs: {
        thinking: true,
        reasoning_effort: "high"
      }
    } as any);

    const messageObj = completion.choices[0]?.message as any;
    const reasoning = messageObj?.reasoning || messageObj?.reasoning_content || "";
    const content = messageObj?.content || "";

    if (content) {
      return NextResponse.json({ text: content, reasoning: reasoning });
    } else {
      console.error("NVIDIA DeepSeek chatbot error: Empty response content", JSON.stringify(completion));
      return NextResponse.json({ error: "Failed to generate response" }, { status: 500 });
    }
  } catch (error: any) {
    console.error("Chatbot API error:", error);
    return NextResponse.json({ error: error.message || "Internal Server Error" }, { status: 500 });
  }
}

