interface Candle {
  time: string;
  open: number;
  high: number;
  low: number;
  close: number;
  volume?: number;
}

const generateFallbackData = (symbol: string): Candle[] => {
  const count = 60;
  const data: Candle[] = [];
  let currentPrice = symbol === "BTCUSD" ? 65120 : symbol === "XAUUSD" ? 2324 : symbol === "US100" ? 19850 : symbol === "USDJPY" ? 157.85 : 1.08450;
  const volatility = symbol === "BTCUSD" ? 80 : symbol === "XAUUSD" ? 2.5 : symbol === "US100" ? 25 : symbol === "USDJPY" ? 0.15 : 0.0006;
  const time = new Date();

  for (let i = 0; i < count; i++) {
    const open = currentPrice;
    const change = (Math.random() - 0.5) * volatility;
    const close = currentPrice + change;
    const high = Math.max(open, close) + Math.random() * (volatility * 0.4);
    const low = Math.min(open, close) - Math.random() * (volatility * 0.4);
    time.setMinutes(time.getMinutes() - 5);

    data.push({
      time: time.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', hour12: false }),
      open: +open.toFixed(symbol === "BTCUSD" ? 0 : symbol === "USDJPY" ? 2 : 5),
      high: +high.toFixed(symbol === "BTCUSD" ? 0 : symbol === "USDJPY" ? 2 : 5),
      low: +low.toFixed(symbol === "BTCUSD" ? 0 : symbol === "USDJPY" ? 2 : 5),
      close: +close.toFixed(symbol === "BTCUSD" ? 0 : symbol === "USDJPY" ? 2 : 5)
    });
    currentPrice = close;
  }
  return data.reverse();
};

const parseAlphaVantageResponse = (json: any): Candle[] => {
  const timeSeriesKey = Object.keys(json).find(k => k.toLowerCase().includes("time series"));
  if (!timeSeriesKey) return [];
  const seriesData = json[timeSeriesKey];
  return Object.keys(seriesData).map(timeStr => {
    const bar = seriesData[timeStr];
    return {
      time: timeStr.substring(11, 16),
      open: parseFloat(bar["1. open"]),
      high: parseFloat(bar["2. high"]),
      low: parseFloat(bar["3. low"]),
      close: parseFloat(bar["4. close"]),
      volume: bar["5. volume"] ? parseFloat(bar["5. volume"]) : undefined
    };
  }).reverse();
};

// ÔöÇÔöÇÔöÇ Charting Component (Alpha Vantage SDK & custom SVG renderer) ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
function SimulatorChart({ symbol }: { symbol: string }) {
  const [isMaximized, setIsMaximized] = useState(false);
  const [candles, setCandles] = useState<Candle[]>([]);
  const [visibleCount, setVisibleCount] = useState(35);
  const [isPlaying, setIsPlaying] = useState(false);
  const [loading, setLoading] = useState(false);
  const [dataSource, setDataSource] = useState<"Alpha Vantage API" | "Simulator Fallback">("Simulator Fallback");

  const [hoverIndex, setHoverIndex] = useState<number | null>(null);
  const [mouseY, setMouseY] = useState<number | null>(null);
  const containerRef = useRef<SVGSVGElement>(null);

  const toggleMaximize = () => {
    setIsMaximized(prev => !prev);
  };

  useEffect(() => {
    if (!isPlaying) return;
    const timer = setInterval(() => {
      setVisibleCount(prev => {
        if (prev >= candles.length) {
          setIsPlaying(false);
          return prev;
        }
        return prev + 1;
      });
    }, 1500);
    return () => clearInterval(timer);
  }, [isPlaying, candles.length]);

  useEffect(() => {
    let active = true;
    const loadData = async () => {
      setLoading(true);
      const apiKey = "GNQTZXZECNJV08FY";
      let url = "";

      if (symbol === "US100" || symbol === "NASDAQ") {
        url = `https://www.alphavantage.co/query?function=TIME_SERIES_INTRADAY&symbol=QQQ&interval=5min&apikey=${apiKey}`;
      } else if (symbol === "BTCUSD") {
        url = `https://www.alphavantage.co/query?function=CRYPTO_INTRADAY&symbol=BTC&market=USD&interval=5min&apikey=${apiKey}`;
      } else if (symbol === "XAUUSD") {
        url = `https://www.alphavantage.co/query?function=FX_INTRADAY&from_symbol=XAU&to_symbol=USD&interval=5min&apikey=${apiKey}`;
      } else {
        const from = symbol.substring(0, 3);
        const to = symbol.substring(3, 6);
        url = `https://www.alphavantage.co/query?function=FX_INTRADAY&from_symbol=${from}&to_symbol=${to}&interval=5min&apikey=${apiKey}`;
      }

      try {
        const res = await fetch(url);
        const json = await res.json();

        if (!active) return;

        if (json["Note"] || json["Information"] || json["Error Message"] || Object.keys(json).length === 0) {
          console.warn("Alpha Vantage fallback: using simulated asset price feeds", json);
          setCandles(generateFallbackData(symbol));
          setDataSource("Simulator Fallback");
        } else {
          const parsed = parseAlphaVantageResponse(json);
          if (parsed.length > 0) {
            setCandles(parsed);
            setDataSource("Alpha Vantage API");
          } else {
            setCandles(generateFallbackData(symbol));
            setDataSource("Simulator Fallback");
          }
        }
      } catch (err) {
        console.error("Alpha Vantage fetch error, using fallback data", err);
        if (active) {
          setCandles(generateFallbackData(symbol));
          setDataSource("Simulator Fallback");
        }
      } finally {
        if (active) {
          setLoading(false);
          setVisibleCount(35);
          setIsPlaying(false);
        }
      }
    };

    loadData();

    return () => {
      active = false;
    };
  }, [symbol]);

  const candlesToShow = candles.slice(0, visibleCount);
  const prices = candlesToShow.flatMap(c => [c.low, c.high]);
  const minPrice = prices.length ? Math.min(...prices) : 0;
  const maxPrice = prices.length ? Math.max(...prices) : 100;
  const priceRange = maxPrice - minPrice;

  const startX = 20;
  const endX = 900;
  const startY = 20;
  const endY = 300;

  const getX = (index: number) => {
    const total = candlesToShow.length;
    if (total <= 1) return startX;
    return startX + (index / (total - 1)) * (endX - startX);
  };

  const getY = (price: number) => {
    if (priceRange === 0) return (startY + endY) / 2;
    return endY - ((price - minPrice) / priceRange) * (endY - startY);
  };

  const smaPoints: { index: number; val: number }[] = [];
  candlesToShow.forEach((c, idx) => {
    if (idx >= 8) {
      const sum = candlesToShow.slice(idx - 8, idx + 1).reduce((s, b) => s + b.close, 0);
      smaPoints.push({ index: idx, val: +(sum / 9) });
    }
  });

  const smaPath = smaPoints.length
    ? smaPoints.map((p, i) => `${i === 0 ? "M" : "L"} ${getX(p.index)} ${getY(p.val)}`).join(" ")
    : "";

  const handleMouseMove = (e: React.MouseEvent<SVGSVGElement, MouseEvent>) => {
    if (!containerRef.current || !candlesToShow.length) return;
    const rect = containerRef.current.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    const viewBoxX = (x / rect.width) * 1000;
    const viewBoxY = (y / rect.height) * 360;

    let nearestIndex = 0;
    let minDiff = Infinity;
    candlesToShow.forEach((c, idx) => {
      const diff = Math.abs(getX(idx) - viewBoxX);
      if (diff < minDiff) {
        minDiff = diff;
        nearestIndex = idx;
      }
    });

    setHoverIndex(nearestIndex);
    setMouseY(viewBoxY);
  };

  const handleMouseLeave = () => {
    setHoverIndex(null);
    setMouseY(null);
  };

  const hoveredCandle = hoverIndex !== null && hoverIndex < candlesToShow.length ? candlesToShow[hoverIndex] : null;

  const gridLinesCount = 5;
  const gridLines = Array.from({ length: gridLinesCount }, (_, i) => {
    const val = minPrice + (priceRange / (gridLinesCount - 1)) * i;
    return {
      y: getY(val),
      val: val.toFixed(symbol === "BTCUSD" ? 0 : symbol === "USDJPY" ? 2 : 5)
    };
  });

  const stepForward = () => {
    if (visibleCount < candles.length) {
      setVisibleCount(prev => prev + 1);
    }
  };

  const resetReplay = () => {
    setVisibleCount(Math.min(30, candles.length));
    setIsPlaying(false);
  };

  const hoveredPrice = mouseY !== null && priceRange > 0
    ? (maxPrice - ((mouseY - startY) / (endY - startY)) * priceRange)
    : 0;

  const renderContent = () => {
    if (loading) {
      return (
        <div className="flex-1 flex flex-col items-center justify-center min-h-[300px] gap-2">
          <RefreshCw className="w-8 h-8 text-gold animate-spin" />
          <p className="text-xs text-desc">Loading Alpha Vantage Live Feeds...</p>
        </div>
      );
    }

    if (!candlesToShow.length) {
      return (
        <div className="flex-1 flex items-center justify-center min-h-[300px] text-xs text-desc">
          No chart data loaded.
        </div>
      );
    }

    return (
      <div className="w-full flex-1 flex flex-col min-h-0 relative select-none">
        <div className="flex flex-wrap items-center justify-between gap-3 px-4 py-2 border-b border-panel-border bg-panel-bg/45 text-[10px] text-desc font-mono">
          <div className="flex items-center gap-4">
            <span className="font-bold text-title">{symbol} 5m</span>
            {hoveredCandle ? (
              <>
                <span>O: <span className={hoveredCandle.close >= hoveredCandle.open ? "text-green-accent" : "text-red-accent"}>{hoveredCandle.open}</span></span>
                <span>H: <span className="text-title">{hoveredCandle.high}</span></span>
                <span>L: <span className="text-title">{hoveredCandle.low}</span></span>
                <span>C: <span className={hoveredCandle.close >= hoveredCandle.open ? "text-green-accent" : "text-red-accent"}>{hoveredCandle.close}</span></span>
              </>
            ) : (
              <span>Hover over candles to view values</span>
            )}
          </div>
          <div className="flex items-center gap-2">
            <span className={`px-2 py-0.5 rounded text-[8px] font-black uppercase ${dataSource === "Alpha Vantage API" ? "bg-green-500/10 text-green-accent" : "bg-purple-500/10 text-purple-400"}`}>
              {dataSource}
            </span>
          </div>
        </div>

        <div className="flex items-center gap-2 px-4 py-1.5 border-b border-panel-border bg-panel-bg/20 text-xs">
          <span className="text-[10px] uppercase font-bold text-desc flex items-center gap-1"><Play className="w-3 h-3 text-purple-400" /> Backtest Control:</span>
          <button onClick={() => setIsPlaying(!isPlaying)} className={`px-2.5 py-1 rounded text-[10px] font-bold uppercase transition-all cursor-pointer ${isPlaying ? "bg-red-500/20 text-red-accent border border-red-500/30" : "bg-purple-600 hover:bg-purple-700 text-white"}`}>
            {isPlaying ? "Pause Replay" : "Play Replay"}
          </button>
          <button onClick={stepForward} disabled={isPlaying || visibleCount >= candles.length} className="px-2 py-1 rounded bg-panel-bg border border-panel-border text-[10px] font-bold text-title uppercase hover:bg-panel-border disabled:opacity-40 cursor-pointer">
            Step Forward
          </button>
          <button onClick={resetReplay} className="px-2 py-1 rounded bg-panel-bg border border-panel-border text-[10px] font-bold text-title uppercase hover:bg-panel-border cursor-pointer">
            Reset
          </button>
          <span className="text-[9px] text-desc ml-auto font-mono">Bar: {visibleCount} / {candles.length}</span>
        </div>

        <div className="flex-1 min-h-[300px] w-full bg-[#0a0a0f] relative overflow-hidden">
          <svg
            ref={containerRef}
            viewBox="0 0 1000 360"
            className="w-full h-full cursor-crosshair"
            onMouseMove={handleMouseMove}
            onMouseLeave={handleMouseLeave}
          >
            {gridLines.map((line, idx) => (
              <g key={idx}>
                <line
                  x1={startX}
                  y1={line.y}
                  x2={endX}
                  y2={line.y}
                  stroke="rgba(255,255,255,0.04)"
                  strokeWidth="1"
                  strokeDasharray="4 4"
                />
                <text
                  x={endX + 15}
                  y={line.y + 4}
                  fill="var(--text-desc)"
                  className="text-[9px] font-mono select-none"
                >
                  {line.val}
                </text>
              </g>
            ))}

            {candlesToShow.filter((_, idx) => idx % Math.max(1, Math.round(candlesToShow.length / 5)) === 0).map((c, idx) => {
              const candleIdx = candlesToShow.findIndex(x => x.time === c.time);
              return (
                <text
                  key={idx}
                  x={getX(candleIdx)}
                  y={endY + 25}
                  fill="var(--text-desc)"
                  className="text-[9px] font-mono text-center select-none"
                  textAnchor="middle"
                >
                  {c.time}
                </text>
              );
            })}

            {smaPath && (
              <path
                d={smaPath}
                fill="none"
                stroke="#6366f1"
                strokeWidth="1.5"
                opacity="0.8"
              />
            )}

            {candlesToShow.map((c, idx) => {
              const x = getX(idx);
              const yOpen = getY(c.open);
              const yClose = getY(c.close);
              const yHigh = getY(c.high);
              const yLow = getY(c.low);
              const isUp = c.close >= c.open;
              const color = isUp ? "#22c55e" : "#ef4444";
              const candleW = Math.max(3, (880 / candlesToShow.length) * 0.7);

              return (
                <g key={idx}>
                  <line
                    x1={x}
                    y1={yHigh}
                    x2={x}
                    y2={yLow}
                    stroke={color}
                    strokeWidth="1.5"
                  />
                  <rect
                    x={x - candleW / 2}
                    y={Math.min(yOpen, yClose)}
                    width={candleW}
                    height={Math.max(1.5, Math.abs(yOpen - yClose))}
                    fill={color}
                    stroke={color}
                    strokeWidth="0.5"
                  />
                </g>
              );
            })}

            {hoverIndex !== null && hoverIndex < candlesToShow.length && (
              <g>
                <line
                  x1={getX(hoverIndex)}
                  y1={startY}
                  x2={getX(hoverIndex)}
                  y2={endY}
                  stroke="rgba(255,255,255,0.2)"
                  strokeWidth="1"
                  strokeDasharray="2 2"
                />
                <circle
                  cx={getX(hoverIndex)}
                  cy={getY(candlesToShow[hoverIndex].close)}
                  r="4"
                  fill="#ffffff"
                  stroke="#a855f7"
                  strokeWidth="1.5"
                />
              </g>
            )}

            {mouseY !== null && mouseY >= startY && mouseY <= endY && (
              <g>
                <line
                  x1={startX}
                  y1={mouseY}
                  x2={endX}
                  y2={mouseY}
                  stroke="rgba(255,255,255,0.2)"
                  strokeWidth="1"
                  strokeDasharray="2 2"
                />
                <rect
                  x={endX + 5}
                  y={mouseY - 8}
                  width={75}
                  height={16}
                  rx="3"
                  fill="#1e1b4b"
                  stroke="#6366f1"
                  strokeWidth="0.5"
                />
                <text
                  x={endX + 42}
                  y={mouseY + 4}
                  fill="#c084fc"
                  className="text-[8px] font-mono select-none font-bold"
                  textAnchor="middle"
                >
                  {hoveredPrice.toFixed(symbol === "BTCUSD" ? 0 : symbol === "USDJPY" ? 2 : 5)}
                </text>
              </g>
            )}
          </svg>
        </div>
      </div>
    );
  };

  return (
    <>
      <div className="relative w-full h-[470px] overflow-hidden rounded-xl border border-panel-border bg-[#050505] flex flex-col">
        {renderContent()}

        {/* Fullscreen Maximize Button Overlay */}
        <button
          onClick={toggleMaximize}
          className="absolute top-10 right-3 z-20 p-2 rounded-lg bg-panel-bg/85 border border-panel-border hover:border-gold hover:text-gold text-sec hover:scale-105 transition-all shadow-lg flex items-center justify-center cursor-pointer"
          title="Maximize Chart"
        >
          <Maximize2 className="w-4 h-4" />
        </button>

        {/* Bottom Overlay Bar */}
        <div className="absolute bottom-0 left-0 right-0 h-[32px] bg-[#1c2030] z-10 border-t border-panel-border flex items-center justify-between px-3 select-none">
          <span className="text-[9px] font-black text-gold uppercase tracking-widest">Alpha Vantage SDK Integration</span>
          <span className="text-[9px] font-black text-desc uppercase tracking-widest opacity-60">Real-Time Data Feed Active</span>
        </div>
      </div>

      {isMaximized && (
        <div className="fixed inset-0 z-50 bg-[#0a0a0f] flex flex-col p-4 animate-fade-in">
          <div className="flex items-center justify-between mb-3 px-2">
            <div className="flex items-center gap-2">
              <span className="w-2.5 h-2.5 rounded-full bg-gold animate-ping" />
              <span className="text-xs font-black text-title uppercase tracking-widest">
                Alpha Vantage Fullscreen Chart (Backtest & Replay Enabled)
              </span>
            </div>
            <button
              onClick={toggleMaximize}
              className="px-3 py-1.5 rounded-lg bg-panel-bg border border-panel-border text-xs text-title hover:bg-red-500/20 hover:text-red-400 transition-all font-extrabold uppercase flex items-center gap-1.5 cursor-pointer"
            >
              <Minimize2 className="w-3.5 h-3.5" /> Close Fullscreen
            </button>
          </div>
          <div className="flex-1 rounded-xl overflow-hidden border border-panel-border bg-[#050505] flex flex-col p-2">
            {renderContent()}
          </div>
        </div>
      )}
    </>
  );
}

