              {openPL >= 0 ? "+" : ""}${openPL.toLocaleString(undefined, { minimumFractionDigits: 2 })}
            </span>
          </div>
        </div>

        {/* Order Form */}
        <div className="glass-panel p-6 rounded-2xl border-panel-border bg-panel-bg space-y-4">
