              <div className="text-[9px] text-gray-400">Trades</div>
            </div>
            <div className="text-center">
              <div className={`text-xl font-black font-mono ${totalPL >= 0 ? "text-green-400" : "text-red-400"}`}>${totalPL.toFixed(0)}</div>
