          {activeTab === "share" && <ShareCardPanel user={user} trades={trades} />}
        </div>
      </div>
    </div>
  );
}

// ÔöÇÔöÇÔöÇ Root with Auth ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
function DashboardWithAuth() {
  const { user, loading } = useFirebaseAuth();
  const [showDashboard, setShowDashboard] = useState(false);

  useEffect(() => {
    if (user) setShowDashboard(true);
  }, [user]);

  if (loading) {
    return (
      <div className="min-h-screen bg-app-bg flex items-center justify-center">
        <div className="text-center space-y-3">
          <div className="w-10 h-10 border-2 border-purple-500 border-t-transparent rounded-full animate-spin mx-auto" />
          <p className="text-xs text-desc">Loading TradinJournal...</p>
        </div>
      </div>
    );
  }

  if (!user || !showDashboard) return <AuthGate onSuccess={() => setShowDashboard(true)} />;
  return <Dashboard />;
}

export default function TradinJournalDashboardPage() {
  return (
    <FirebaseAuthProvider>
      <DashboardWithAuth />
    </FirebaseAuthProvider>
  );
}

