          <p className="text-xs text-desc">Loading VIP Signals...</p>
        </div>
      </div>
    );
  }

  if (!user || !authed) return <VIPAuthGate onSuccess={() => setAuthed(true)} />;
  return <VIPDashboard />;
}

export default function VIPSignalsPage() {
  return (
    <FirebaseAuthProvider>
      <VIPSignalsRoot />
