export const FirebaseAuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<FBUser | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // Listen to Auth State Changes
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (firebaseUser) => {
      if (firebaseUser) {
        try {
          const userDocRef = doc(db, "users", firebaseUser.uid);
          const userDocSnap = await getDoc(userDocRef);

          if (userDocSnap.exists()) {
            const existingData = userDocSnap.data() as FBUser;
            const updatedUser: FBUser = {
              ...existingData,
              trades: existingData.trades || [],
              balance: existingData.balance ?? 100000
            };
            setUser(updatedUser);
          } else {
            // Document doesn't exist in Firestore yet (e.g. initial Google login or signup interrupted)
            const nameParts = (firebaseUser.displayName || "").split(" ");
            const firstName = nameParts[0] || "Trader";
            const lastName = nameParts.slice(1).join(" ") || "";
            const now = new Date().toISOString();

            const fallbackUser: FBUser = {
              uid: firebaseUser.uid,
              firstName,
              lastName,
              displayName: firebaseUser.displayName || "Trader",
              email: firebaseUser.email || "",
              phone: firebaseUser.phoneNumber || "",
              photoURL: firebaseUser.photoURL || null,
              emailVerified: firebaseUser.emailVerified,
              createdAt: now,
              loginHistory: [now],
              enrolledProducts: [],
              courseProgress: {},
              trades: [],
              balance: 100000
            };

            await setDoc(userDocRef, fallbackUser);
            setUser(fallbackUser);
          }
        } catch (err) {
          console.error("Error fetching user document on state change:", err);
          // Construct fallback user from auth data
          const nameParts = (firebaseUser.displayName || "").split(" ");
          const firstName = nameParts[0] || "Trader";
          const lastName = nameParts.slice(1).join(" ") || "";
          const now = new Date().toISOString();

          setUser({
            uid: firebaseUser.uid,
            firstName,
            lastName,
            displayName: firebaseUser.displayName || "Trader",
            email: firebaseUser.email || "",
            phone: firebaseUser.phoneNumber || "",
            photoURL: firebaseUser.photoURL || null,
            emailVerified: firebaseUser.emailVerified,
            createdAt: now,
            loginHistory: [now],
            enrolledProducts: [],
            courseProgress: {},
            trades: [],
            balance: 100000
          });
        }
      } else {
        setUser(null);
      }
      setLoading(false);
    });

    return () => unsubscribe();
  }, []);

  const clearError = useCallback(() => setError(null), []);

  // ÔöÇÔöÇ Sign Up ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const signUp = useCallback(async (data: SignUpData): Promise<boolean> => {
    setLoading(true);
    setError(null);
    try {
      const userCredential = await createUserWithEmailAndPassword(auth, data.email, data.password);
      const firebaseUser = userCredential.user;

      const displayName = `${data.firstName} ${data.lastName}`;
      await updateProfile(firebaseUser, { displayName });

      const now = new Date().toISOString();
      const dbUser: FBUser = {
        uid: firebaseUser.uid,
        firstName: data.firstName,
        lastName: data.lastName,
        displayName,
        email: data.email.toLowerCase().trim(),
        phone: data.phone || "",
        photoURL: firebaseUser.photoURL || null,
        emailVerified: firebaseUser.emailVerified,
        createdAt: now,
        loginHistory: [now],
        enrolledProducts: [],
        courseProgress: {},
        trades: [],
        balance: 100000
      };

      await setDoc(doc(db, "users", firebaseUser.uid), dbUser);
      setUser(dbUser);
      setLoading(false);
      return true;
    } catch (err: any) {
      console.error("SignUp error:", err);
      let msg = err.message || "Sign up failed.";
      if (err.code === "auth/email-already-in-use") {
        msg = "An account with this email already exists. Please sign in.";
      } else if (err.code === "auth/invalid-email") {
        msg = "The email address is invalid.";
      } else if (err.code === "auth/weak-password") {
        msg = "Password must be at least 6 characters.";
      }
      setError(msg);
      setLoading(false);
      return false;
    }
  }, []);

  // ÔöÇÔöÇ Sign In ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const signIn = useCallback(async (email: string, password: string): Promise<boolean> => {
    setLoading(true);
    setError(null);
    try {
      const userCredential = await signInWithEmailAndPassword(auth, email, password);
      const firebaseUser = userCredential.user;

      const userDocRef = doc(db, "users", firebaseUser.uid);
      const userDocSnap = await getDoc(userDocRef);

      let dbUser: FBUser;
      const now = new Date().toISOString();

      if (userDocSnap.exists()) {
        const existingData = userDocSnap.data() as FBUser;
        const updatedHistory = [now, ...(existingData.loginHistory || [])].slice(0, 20);

        dbUser = {
          ...existingData,
          displayName: firebaseUser.displayName || existingData.displayName,
          emailVerified: firebaseUser.emailVerified,
          loginHistory: updatedHistory,
          trades: existingData.trades || [],
          balance: existingData.balance ?? 100000
        };

        await updateDoc(userDocRef, {
          loginHistory: updatedHistory,
          trades: dbUser.trades,
          balance: dbUser.balance
        });
      } else {
        const nameParts = (firebaseUser.displayName || "").split(" ");
        const firstName = nameParts[0] || "Trader";
        const lastName = nameParts.slice(1).join(" ") || "";
        dbUser = {
          uid: firebaseUser.uid,
          firstName,
          lastName,
          displayName: firebaseUser.displayName || "Trader",
          email: firebaseUser.email || email,
          phone: firebaseUser.phoneNumber || "",
          photoURL: firebaseUser.photoURL || null,
          emailVerified: firebaseUser.emailVerified,
          createdAt: now,
          loginHistory: [now],
          enrolledProducts: [],
          courseProgress: {},
          trades: [],
          balance: 100000
        };
        await setDoc(userDocRef, dbUser);
      }

      setUser(dbUser);
      setLoading(false);
      return true;
    } catch (err: any) {
      console.error("SignIn error:", err);
      let msg = err.message || "Sign in failed.";
      if (
        err.code === "auth/user-not-found" ||
        err.code === "auth/wrong-password" ||
        err.code === "auth/invalid-credential"
      ) {
        msg = "Incorrect email or password. Please try again.";
      }
      setError(msg);
      setLoading(false);
      return false;
    }
  }, []);

  // ÔöÇÔöÇ Google Sign In ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const signInWithGoogle = useCallback(async (): Promise<boolean> => {
    setLoading(true);
    setError(null);
    try {
      const provider = new GoogleAuthProvider();
      const userCredential = await signInWithPopup(auth, provider);
      const firebaseUser = userCredential.user;

      const userDocRef = doc(db, "users", firebaseUser.uid);
      const userDocSnap = await getDoc(userDocRef);

      let dbUser: FBUser;
      const now = new Date().toISOString();

      if (userDocSnap.exists()) {
        const existingData = userDocSnap.data() as FBUser;
        const updatedHistory = [now, ...(existingData.loginHistory || [])].slice(0, 20);

        dbUser = {
          ...existingData,
          displayName: firebaseUser.displayName || existingData.displayName,
          emailVerified: firebaseUser.emailVerified,
          loginHistory: updatedHistory,
          trades: existingData.trades || [],
          balance: existingData.balance ?? 100000
        };

        await updateDoc(userDocRef, {
          loginHistory: updatedHistory,
          trades: dbUser.trades,
          balance: dbUser.balance
        });
      } else {
        const nameParts = (firebaseUser.displayName || "").split(" ");
        const firstName = nameParts[0] || "Google";
        const lastName = nameParts.slice(1).join(" ") || "User";
        dbUser = {
          uid: firebaseUser.uid,
          firstName,
          lastName,
          displayName: firebaseUser.displayName || "Google User",
          email: firebaseUser.email || "",
          phone: firebaseUser.phoneNumber || "",
          photoURL: firebaseUser.photoURL || null,
          emailVerified: firebaseUser.emailVerified,
          createdAt: now,
          loginHistory: [now],
          enrolledProducts: [],
          courseProgress: {},
          trades: [],
          balance: 100000
        };
        await setDoc(userDocRef, dbUser);
      }

      setUser(dbUser);
      setLoading(false);
      return true;
    } catch (err: any) {
      console.error("Google Sign-In error:", err);
      let msg = err.message || "Google Sign-In failed.";
      if (err.code === "auth/popup-closed-by-user") {
        msg = "Google sign-in popup was closed before completing.";
      }
      setError(msg);
      setLoading(false);
      return false;
    }
  }, []);

  // ÔöÇÔöÇ Sign Out ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const signOut = useCallback(() => {
    setLoading(true);
    fbSignOut(auth)
      .then(() => {
        setUser(null);
        setLoading(false);
      })
      .catch((err) => {
        console.error("SignOut error:", err);
        setLoading(false);
      });
  }, []);

  // ÔöÇÔöÇ Reset Password ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const resetPassword = useCallback(async (email: string): Promise<boolean> => {
    setError(null);
    try {
      await sendPasswordResetEmail(auth, email);
      return true;
    } catch (err: any) {
      console.error("ResetPassword error:", err);
      let msg = err.message || "Failed to send reset link.";
      if (err.code === "auth/user-not-found") {
        msg = "No account found with this email.";
      }
      setError(msg);
      return false;
    }
  }, []);

  // ÔöÇÔöÇ Enroll Product ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const enrollProduct = useCallback((productId: string) => {
    if (!user) return;
    if (user.enrolledProducts.includes(productId)) return;

    const updatedProducts = [...user.enrolledProducts, productId];
    const updated: FBUser = {
      ...user,
      enrolledProducts: updatedProducts
    };

    setUser(updated);

    const userDocRef = doc(db, "users", user.uid);
    updateDoc(userDocRef, { enrolledProducts: arrayUnion(productId) }).catch((err) => {
      console.error("EnrollProduct Firestore error:", err);
    });
  }, [user]);

  // ÔöÇÔöÇ Update Lesson Progress ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const updateLessonProgress = useCallback((productId: string, lessonId: string, done: boolean) => {
    if (!user) return;

    const currentProgress = user.courseProgress[productId] || {};
    const updated: FBUser = {
      ...user,
      courseProgress: {
        ...user.courseProgress,
        [productId]: {
          ...currentProgress,
          [lessonId]: done
        }
      }
    };

    setUser(updated);

    const userDocRef = doc(db, "users", user.uid);
    updateDoc(userDocRef, {
      [`courseProgress.${productId}.${lessonId}`]: done
    }).catch((err) => {
      console.error("UpdateLessonProgress Firestore error:", err);
    });
  }, [user]);

  // ÔöÇÔöÇ Save Simulator Trade ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const saveTrade = useCallback(async (trade: Trade) => {
    if (!user) return;

    const updatedTrades = [trade, ...(user.trades || [])];
    const updated: FBUser = {
      ...user,
      trades: updatedTrades
    };

    setUser(updated);

    const userDocRef = doc(db, "users", user.uid);
    await updateDoc(userDocRef, {
      trades: arrayUnion(trade)
    }).catch((err) => {
      console.error("SaveTrade Firestore error:", err);
    });
  }, [user]);

  // ÔöÇÔöÇ Update Simulator Balance ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const updateBalance = useCallback(async (newBalance: number) => {
    if (!user) return;

    const updated: FBUser = {
      ...user,
      balance: newBalance
    };

    setUser(updated);

    const userDocRef = doc(db, "users", user.uid);
    await updateDoc(userDocRef, {
      balance: newBalance
    }).catch((err) => {
      console.error("UpdateBalance Firestore error:", err);
    });
  }, [user]);

  return (
    <FirebaseAuthContext.Provider
      value={{
        user,
        loading,
        error,
        signUp,
        signIn,
        signInWithGoogle,
        signOut,
        resetPassword,
        enrollProduct,
        updateLessonProgress,
        clearError,
        saveTrade,
        updateBalance
      }}
    >
      {children}
    </FirebaseAuthContext.Provider>
  );
};

// ÔöÇÔöÇÔöÇ Hook ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

export const useFirebaseAuth = (): AuthContextType => {
  const ctx = useContext(FirebaseAuthContext);
  if (!ctx) throw new Error("useFirebaseAuth must be used within FirebaseAuthProvider");
  return ctx;
};
